import os
from google.cloud import storage
from google.cloud import firestore
from google.cloud.pubsub import PublisherClient

def process_file(event, context):
    bucket_name = event['bucket']
    source_blob_name = event['name']

    storage_client = storage.Client()
    bucket = storage_client.get_bucket(bucket_name)
    blob = bucket.blob(source_blob_name)

    data = blob.download_as_string()
    firestore_client = firestore.Client()
    db = firestore_client.client

    doc_ref = db.collection(u'your-collection').document()
    doc_ref.set({
        u'data': data,
    })

    pubsub_client = PublisherClient()
    topic_path = pubsub_client.topic_path('your-project', 'your-topic')
    pubsub_client.publish(topic_path, data.encode())